-- Step 2: Sync equipment_manufacturers from pedal_brands
insert into public.equipment_manufacturers (name, slug, is_active)
select pb.name, pb.slug, true
from public.pedal_brands pb
on conflict (slug) do update set
  name = excluded.name,
  is_active = true,
  updated_at = now();

